void apartamentosConVistas(const vector<Edificio>& edificios, vector<string>& vistas) {
    int alturaMaximaVista = 0;
    // Recorrer los edificios desde el mar hacia el interior
    for (int i = edificios.size() - 1; i >= 0; --i) {
        // Comparar la altura del piso más alto que se vende
        if (edificios[i].alturaPiso > alturaMaximaVista) {
            // Añadir identificador al resultado
            vistas.push_back(edificios[i].identificador);
            // Actualizar la altura máxima vista
            alturaMaximaVista = edificios[i].alturaPiso;
        }
    }
    // Invertir el vector de vistas para que estén desde el mar hacia el interior
    reverse(vistas.begin(), vistas.end());
}
